    sprints, board.id, chrono::Utc::now(),
);
let current_sprint_id = self.get_selected_card_in_context()
    .and_then(|c| c.sprint_id);
let selection_idx = crate::components::sprint_assign_list::default_selection_index(
    &entries, current_sprint_id,
).unwrap_or(0);
self.dialog_input.sprint_assign_selection.set(Some(selection_idx));
```

3. **Update the bulk handler** at `card_handlers.rs:88-90` to call the same helper with `current_sprint_id = None`:

```rust
