```rust
//! Per-session undo/redo history.
//!
//! Generic over the consumer's command type. In-memory; never persisted;
//! lifetime tied to the running session.

use crate::Command;

#[derive(Debug, Clone)]
pub struct UndoEntry<Cmd: Command> {
    pub forward: Vec<Cmd>,
    pub inverse: Vec<Cmd>,
}

#[derive(Debug, Clone)]
pub struct UndoStack<Cmd: Command> {
    entries: Vec<UndoEntry<Cmd>>,
    cursor: usize,
}

impl<Cmd: Command> Default for UndoStack<Cmd> {
    fn default() -> Self {
        Self { entries: Vec::new(), cursor: 0 }
    }
}

impl<Cmd: Command> UndoStack<Cmd> {
    pub fn new() -> Self { Self::default() }

    pub fn push(&mut self, entry: UndoEntry<Cmd>) {
        self.entries.truncate(self.cursor);
        self.entries.push(entry);
        self.cursor = self.entries.len();
    }

    pub fn peek_undo(&self) -> Option<&UndoEntry<Cmd>> {
        if self.cursor == 0 { return None; }
        self.entries.get(self.cursor - 1)
    }

    pub fn peek_redo(&self) -> Option<&UndoEntry<Cmd>> {
        if self.cursor >= self.entries.len() { return None; }
        self.entries.get(self.cursor)
    }

    pub fn commit_undo(&mut self) -> bool {
        if self.cursor == 0 { return false; }
        self.cursor -= 1;
        true
    }

    pub fn commit_redo(&mut self) -> bool {
        if self.cursor >= self.entries.len() { return false; }
        self.cursor += 1;
        true
    }

    pub fn clear(&mut self) {
        self.entries.clear();
        self.cursor = 0;
    }

    pub fn undo_depth(&self) -> usize { self.cursor }
    pub fn redo_depth(&self) -> usize { self.entries.len().saturating_sub(self.cursor) }
    pub fn can_undo(&self) -> bool { self.cursor > 0 }
    pub fn can_redo(&self) -> bool { self.cursor < self.entries.len() }
}
```

Re-export from `lib.rs`:
```rust
