//! Generic command-executor wrapper around a `Backend` with undo/redo
//! history. Knows nothing about kanban or any other domain.

use crate::{Backend, BackendExecutor, Command, CoreResult, UndoStack};
use std::sync::Arc;

pub struct Context<B, Cmd>
where
    B: Backend + BackendExecutor<Cmd> + ?Sized,
    Cmd: Command,
{
    backend: Arc<B>,
    undo_stack: UndoStack<Cmd>,
    dirty: bool,
}

impl<B, Cmd> Context<B, Cmd>
where
    B: Backend + BackendExecutor<Cmd> + ?Sized,
    Cmd: Command,
{
    pub fn new(backend: Arc<B>) -> Self {
        Self { backend, undo_stack: UndoStack::new(), dirty: false }
    }

    pub fn backend(&self) -> Arc<B> {
        Arc::clone(&self.backend)
    }

    pub fn replace_backend(&mut self, backend: Arc<B>) {
        tracing::info!("Replacing backend; undo/redo history discarded");
        self.backend = backend;
        self.undo_stack.clear();
        self.dirty = false;
    }

    pub fn can_undo(&self) -> bool { self.undo_stack.can_undo() }
    pub fn can_redo(&self) -> bool { self.undo_stack.can_redo() }
    pub fn undo_depth(&self) -> usize { self.undo_stack.undo_depth() }
    pub fn redo_depth(&self) -> usize { self.undo_stack.redo_depth() }
    pub fn clear_history(&mut self) { self.undo_stack.clear() }

    pub fn is_dirty(&self) -> bool { self.dirty }
    pub fn mark_dirty(&mut self) { self.dirty = true }
    pub fn mark_clean(&mut self) { self.dirty = false }

    pub async fn save(&self) -> CoreResult<()> {
        self.backend.flush().await
    }

    pub async fn reload(&mut self) -> CoreResult<()> {
        self.backend.reload().await?;
        self.undo_stack.clear();
        self.dirty = false;
        Ok(())
    }
}
```

Re-export from `lib.rs`:
```rust
