    /// Metadata about the underlying persistence store. Returns `None` for
    /// in-memory backends. KANBAN-SPECIFIC — references kanban-persistence
    /// types, stays here.
    fn persistence_metadata(&self) -> Option<PersistenceMetadata> { None }
}
```

