```

Hard-coded to `Vec<Vec<Command>>`. No per-batch metadata.

## Target shape
New file `crates/kanban-core/src/command_record.rs` (placeholder from Scaffolding):
```rust
use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

/// One audit-log entry: a forward batch of `C` commands plus
/// when-and-by-whom metadata. `C` is the consumer's command enum.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CommandRecord<C> {
    pub id: Uuid,
    pub timestamp: DateTime<Utc>,
    pub commands: Vec<C>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub actor: Option<String>,
}

impl<C> CommandRecord<C> {
    pub fn new(commands: Vec<C>) -> Self {
        Self {
            id: Uuid::new_v4(),
            timestamp: Utc::now(),
            commands,
            actor: None,
        }
    }
}

/// Append-only chronological log of executed batches. Generic over the
/// command type so kanban and the SRS app share the trait and only
/// instantiate `C` differently.
pub trait CommandLog<C>: Send + Sync {
    type Err;
    fn append(&self, record: &CommandRecord<C>) -> Result<u64, Self::Err>;
    fn count(&self) -> Result<u64, Self::Err>;
    fn load(&self, from: u64, to: u64) -> Result<Vec<CommandRecord<C>>, Self::Err>;
    fn load_all(&self) -> Result<(Vec<CommandRecord<C>>, u64), Self::Err> {
        let n = self.count()?;
        let recs = self.load(0, n)?;
        Ok((recs, n))
    }
}
```

Re-export from `lib.rs`:
```rust
pub use command_record::{CommandLog, CommandRecord};
```

