use crate::{CoreError, CoreResult};
use std::path::{Path, PathBuf};

pub fn validate_path(path: &Path) -> CoreResult<PathBuf> {
    let cwd = std::env::current_dir()
        .map_err(|e| CoreError::Validation(format!("cannot read cwd: {e}")))?;
    validate_path_with_cwd(path, &cwd)
}

fn validate_path_with_cwd(path: &Path, cwd: &Path) -> CoreResult<PathBuf> {
    // body identical to service version with error type swapped
    if path.is_absolute() {
        Ok(dunce::canonicalize(path).unwrap_or_else(|_| path.to_path_buf()))
    } else {
        let canonical_cwd = dunce::canonicalize(cwd).unwrap_or_else(|_| cwd.to_path_buf());
        let resolved = canonical_cwd.join(path);
        let canonical = dunce::canonicalize(&resolved)
            .unwrap_or_else(|_| normalize_path(&resolved));
        if !canonical.starts_with(&canonical_cwd) {
            return Err(CoreError::Validation(format!(
                "Path traversal not allowed: '{}' resolves outside current directory",
                path.display()
            )));
        }
        Ok(canonical)
    }
}

fn normalize_path(path: &Path) -> PathBuf {
    // identical to service version
}
```

