```rust
//! Cross-platform filesystem helpers.

use std::path::Path;
use std::time::Duration;

/// Best-effort `remove_file` with linear backoff. On Windows, the OS may
/// briefly hold a file handle after a long-lived resource (e.g. an sqlx
/// SQLite pool) closes; retrying with backoff lets the OS catch up.
pub async fn remove_file_with_windows_retry(path: &Path) {
    for delay_ms in [0u64, 50, 100, 200, 400] {
        if delay_ms > 0 {
            tokio::time::sleep(Duration::from_millis(delay_ms)).await;
        }
        if std::fs::remove_file(path).is_ok() { return; }
        if !path.exists() { return; }
    }
    tracing::warn!(
        path = %path.display(),
        "failed to remove file after retry backoff; orphan may remain on disk"
    );
}

/// Remove `path` and its SQLite WAL/SHM sidecars (best-effort).
/// Renamed from `cleanup_destination_files` for descriptiveness.
pub async fn cleanup_sqlite_artifacts(path: &str) {
    remove_file_with_windows_retry(Path::new(path)).await;
    let wal = format!("{path}-wal");
    let shm = format!("{path}-shm");
    remove_file_with_windows_retry(Path::new(&wal)).await;
    remove_file_with_windows_retry(Path::new(&shm)).await;
}
```

